code = """import json
import pandas as pd
import re

# Load clinical data
with open(locals()['var_function-call-10491746352253551274'], 'r') as f:
    clinical_data = json.load(f)

# Load mutation data
with open(locals()['var_function-call-4556743781996837205'], 'r') as f:
    mutation_data = json.load(f)

mutated_barcodes = set(row['ParticipantBarcode'] for row in mutation_data)

processed_data = []
for entry in clinical_data:
    desc = entry['Patient_description']
    hist_type = entry['histological_type']
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if match:
        barcode = match.group(1)
        is_mutated = barcode in mutated_barcodes
        processed_data.append({
            'histological_type': hist_type,
            'is_mutated': is_mutated,
            'barcode': barcode
        })

df = pd.DataFrame(processed_data)
print("Total patients extracted:", len(df))
print("Mutated patients count:", df['is_mutated'].sum())

if not df.empty:
    crosstab = pd.crosstab(df['histological_type'], df['is_mutated'])
    print("Full Crosstab:")
    print(crosstab.to_json())
    
    row_totals = crosstab.sum(axis=1)
    print("Row Totals:")
    print(row_totals.to_json())

    valid_types = row_totals[row_totals > 10].index
    filtered_crosstab = crosstab.loc[valid_types]
    print("Filtered Crosstab:")
    print(filtered_crosstab.to_json())
    
    print("Unique Histological Types:", df['histological_type'].unique())

print("__RESULT__:")
print(json.dumps("Debug Info Printed"))"""

